+        assert_eq!(index.documents().len(), 1);
+
+        let new_docs = vec![
+            make_doc("new alpha", 2000, SearchDocumentSource::Scrollback),
+            make_doc("new beta", 2100, SearchDocumentSource::Scrollback),
+        ];
